async function lookupIdentity(agentId, registryAddress, client) {
  try {
    const [agentURI, wallet] = await Promise.all([
      client.readContract({
        address: registryAddress,
        abi: ERC8004_ABI,
        functionName: "tokenURI",
        args: [agentId]
      }),
      client.readContract({
        address: registryAddress,
        abi: ERC8004_ABI,
        functionName: "getAgentWallet",
        args: [agentId]
      })
    ]);
    if (!agentURI)
      return null;
    return { agentId, wallet, agentURI };
  } catch {
    return null;
  }
}

