// src/app.ts
var facilitator = new x402Facilitator;
facilitator.register(BASE_SEPOLIA_CAIP2, new ExactEvmScheme(facilitatorSigner)).onBeforeVerify((ctx) => onBeforeVerify(ctx, verifyDeps)).onBeforeSettle(onBeforeSettle).onAfterSettle(onAfterSettle);
var app2 = new Hono2;
app2.get("/supported", (c) => c.json(facilitator.getSupported()));
app2.post("/verify", async (c) => {
  const body = await c.req.json();
  const result = await facilitator.verify(body.paymentPayload, body.paymentRequirements);
  return c.json(result);
});
app2.post("/settle", async (c) => {
  const body = await c.req.json();
  const result = await facilitator.settle(body.paymentPayload, body.paymentRequirements);
  return c.json(result);
});
app2.route("/mandates", mandates_default);
var app_default = app2;

// src/vercel.ts
var vercel_default = app_default.fetch;
export {
  vercel_default as default
};
